88	/// Parse CLI, run warmup + measurement on two single-thread
89	/// ping-pong actors, print message count + throughput, then
90	/// render the per-dispatch band-table report.
91	fn main() {
92	    let cli = Cli::parse();
93	
94	    println!("{} {}", env!("CARGO_PKG_NAME"), env!("CARGO_PKG_VERSION"),);
95	
96	    // Pin the main thread before any work — calibration and the
97	    // dispatch loop both run here, so they share the pinned core.
98	    let pin_core: Option<usize> = match cli.pin.as_deref() {
99	        None => None,
100	        Some(spec) => match pin::parse_cores(spec) {
101	            Ok(cores) => cores.first().copied(),
102	            Err(e) => {
103	                eprintln!("error: --pin: {e}");
104	                std::process::exit(2);
105	            }
106	        },
107	    };
108	    pin::pin_current(pin_core);
109	
110	    let mut rt = SingleThreadRuntime::new("goal1.dispatch");
111	    let a_id = rt.add_actor(Box::new(PingPongActor { peer_id: 1 }));
112	    let b_id = rt.add_actor(Box::new(PingPongActor { peer_id: 0 }));
113	    assert_eq!((a_id, b_id), (0, 1));
114	    rt.seed(a_id, Message);
115	
116	    // Warmup: same loop, probe active, records discarded at the boundary.
117	    rt.run_for(Duration::from_secs_f64(cli.warmup), cli.inner);
118	    rt.probe_mut().clear();
119	
120	    // Calibration (skipped with --raw). Runs on the warmed system,
121	    // before measurement begins, so freq/cache state matches what
122	    // the probe will see during measurement.
123	    let overhead = if cli.raw {
124	        None
125	    } else {
126	        Some(perf::calibrate())
127	    };
128	
129	    // Measurement.
130	    let count = rt.run_for(Duration::from_secs_f64(cli.duration_s), cli.inner);
131	    let mmps = count as f64 / cli.duration_s / 1e6;
132	    println!(
133	        "goal1: {count} messages in {:.3}s ({mmps:.3} M msg/s, inner={})",
134	        cli.duration_s, cli.inner,
135	    );
136	    match pin_core {
137	        Some(c) => println!("  pinning: main → core {c}"),
138	        None => println!("  pinning: none (unpinned)"),
139	    }
140	    if let Some(ovh) = &overhead {
141	        let framing_ns = ovh.framing_ticks as f64 / ticks::ticks_per_ns();
142	        let per_event_tk = ovh.per_event_ticks(cli.inner);
143	        let per_event_ns = per_event_tk as f64 / ticks::ticks_per_ns();
144	        println!(
145	            "  apparatus: framing={} tk ({:.2} ns); per-event at inner={} = {} tk ({:.2} ns)",
146	            ovh.framing_ticks, framing_ns, cli.inner, per_event_tk, per_event_ns,
147	        );
148	    } else {
149	        println!("  apparatus: raw (no overhead subtraction)");
150	    }
151	    println!();
152	    rt.probe_mut().report(cli.ticks, overhead.as_ref());
153	}
